create table dirkspzm32.db_trace (
    db_act_log_id      number(*, 0) not null enable,
    log_date           date not null enable,
    audsid             number(*, 0) not null enable,
    bg_job_id          number(*, 0),
    client_os_user     varchar2(30 char),
    client_host        varchar2(64 char),
    terminal           varchar2(16 char),
    program            varchar2(64 char),
    client_module_info varchar2(48 char),
    client_action_info varchar2(32 char),
    client_info        varchar2(64 char),
    client_identifier  varchar2(64 char),
    isiusr             varchar2(64 char),
    act_table          varchar2(30 char) not null enable,
    act_pk_cols        varchar2(4000 char) not null enable,
    act_pk_values      varchar2(4000 char) not null enable,
    act_command        varchar2(50 char) not null enable,
    act_info           varchar2(255 char),
    transactionid      varchar2(50 char)
);

alter table dirkspzm32.db_trace
    add constraint pk_db_trace primary key ( db_act_log_id )
        using index enable;


